import { IMessageDataWrapper, IMessageParser } from '@nitrots/nitro-renderer';

export class DiscordVerificationRequiredParser implements IMessageParser
{
private _code: string = '';
private _serverTag: string = '';

public flush(): boolean
{
this._code = '';
this._serverTag = '';
return true;
}

public parse(wrapper: IMessageDataWrapper): boolean
{
if(!wrapper) return false;

this._code = wrapper.readString() || '';
this._serverTag = wrapper.readString() || '';
return true;
}

public get code(): string
{
return this._code;
}

public get serverTag(): string
{
return this._serverTag;
}
}
